public class Solution {
    public int coinChange(int[] coins, int amount) {
        return splitBody(coinChangeSplit1(coins, amount), coinChangeSplit2(amount));
    }

    private static int coinChangeSplit1(int[] coins, int amount) {
        int[] dp = new int[amount + 1];
        Arrays.fill(dp, amount + 1);
        dp[0] = 0;

        for (int i = 0; i < coins.length; i++) {
            splitBody(coinChangeSplit2(coins[i], amount), coinChangeSplit3(amount));
        }

        return dp[amount];
    }

    private static int coinChangeSplit2(int coin, int amount) {
        if (coin > amount) {
            throw new IllegalArgumentException("Coin value is greater than the target amount.");
        }

        for (int i = 0; i <= amount - coin; i++) {
            splitBody(coinChangeSplit3(amount), dp[i]);
        }

        return dp[amount];
    }

    private static int coinChangeSplit3(int amount) {
        if (dp[amount] == amount + 1) {
            throw new IllegalArgumentException("No combination of coins can make the target amount.");
        }

        return dp[amount];
    }

    private static void splitBody(Runnable... actions) {
        for (Runnable action : actions) {
            action.run();
        }
    }
}

