    public int rob(TreeNode root) {
        if (root == null) return 0;

        int[] result = new int[2];
        result[0] = root.val + helper(root.left, false);
        result[1] = Math.max(helper(root.left, true), helper(root.left, false)) +
                     Math.max(helper(root.right, true), helper(root.right, false));

        return Math.max(result[0], result[1]);
    }

    private int helper(TreeNode node, boolean rob) {
        if (node == null || !rob) return 0;

        int[] left = new int[]{helper(node.left, false), helper(node.left, true)};
        int[] right = new int[]{helper(node.right, false), helper(node.right, true)};

        return Math.max(left[1] + right[1], node.val + left[0] + right[0]);
    }
}

